WITH p AS(SELECT 5690000000023241 pp,2026 yy,4 mm),a AS(SELECT t.*,
CASE WHEN lv=0 THEN COALESCE((SELECT SUM(kd) FROM v_aw_m x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0)+COALESCE((SELECT kd FROM v_aw_lm x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=1 THEN COALESCE((SELECT SUM(kd) FROM v_aw_m x,p WHERE x.pid=t.id AND x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=2 THEN COALESCE((SELECT SUM(kd) FROM v_aw_m x,p WHERE x.sid=t.id AND x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=3 THEN COALESCE((SELECT kd FROM v_aw_m x,p WHERE x.cid=t.cid AND x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=9 THEN COALESCE((SELECT kd FROM v_aw_lm x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) ELSE 0 END bykd,
CASE WHEN lv=0 THEN COALESCE((SELECT SUM(kd) FROM v_aw_y x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy),0)+COALESCE((SELECT kd FROM v_aw_ly x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy),0) WHEN lv=1 THEN COALESCE((SELECT SUM(kd) FROM v_aw_y x,p WHERE x.pid=t.id AND x.phid_pc=t.phid_pc AND x.yr=p.yy),0) WHEN lv=2 THEN COALESCE((SELECT SUM(kd) FROM v_aw_y x,p WHERE x.sid=t.id AND x.phid_pc=t.phid_pc AND x.yr=p.yy),0) WHEN lv=3 THEN COALESCE((SELECT kd FROM v_aw_y x,p WHERE x.cid=t.cid AND x.phid_pc=t.phid_pc AND x.yr=p.yy),0) WHEN lv=9 THEN COALESCE((SELECT kd FROM v_aw_ly x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy),0) ELSE 0 END bnljkd,
CASE WHEN lv=0 THEN COALESCE((SELECT SUM(kd) FROM v_aw_a x WHERE x.phid_pc=t.phid_pc),0)+COALESCE((SELECT kd FROM v_aw_la x WHERE x.phid_pc=t.phid_pc),0) WHEN lv=1 THEN COALESCE((SELECT SUM(kd) FROM v_aw_a x WHERE x.pid=t.id AND x.phid_pc=t.phid_pc),0) WHEN lv=2 THEN COALESCE((SELECT SUM(kd) FROM v_aw_a x WHERE x.sid=t.id AND x.phid_pc=t.phid_pc),0) WHEN lv=3 THEN COALESCE((SELECT kd FROM v_aw_a x WHERE x.cid=t.cid AND x.phid_pc=t.phid_pc),0) WHEN lv=9 THEN COALESCE((SELECT kd FROM v_aw_la x WHERE x.phid_pc=t.phid_pc),0) ELSE 0 END kgljkd,
CASE WHEN lv=0 THEN COALESCE((SELECT SUM(yf) FROM v_aw_m x,p WHERE x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=1 THEN COALESCE((SELECT SUM(yf) FROM v_aw_m x,p WHERE x.pid=t.id AND x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=2 THEN COALESCE((SELECT SUM(yf) FROM v_aw_m x,p WHERE x.sid=t.id AND x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) WHEN lv=3 THEN COALESCE((SELECT yf FROM v_aw_m x,p WHERE x.cid=t.cid AND x.phid_pc=t.phid_pc AND x.yr=p.yy AND x.mon=p.mm),0) ELSE 0 END byysgck,
CASE WHEN lv=0 THEN COALESCE((SELECT SUM(yf) FROM v_aw_a x WHERE x.phid_pc=t.phid_pc),0) WHEN lv=1 THEN COALESCE((SELECT SUM(yf) FROM v_aw_a x WHERE x.pid=t.id AND x.phid_pc=t.phid_pc),0) WHEN lv=2 THEN COALESCE((SELECT SUM(yf) FROM v_aw_a x WHERE x.sid=t.id AND x.phid_pc=t.phid_pc),0) WHEN lv=3 THEN COALESCE((SELECT yf FROM v_aw_a x WHERE x.cid=t.cid AND x.phid_pc=t.phid_pc),0) ELSE 0 END kgljysgck
FROM v_aw_e t,p WHERE t.phid_pc=p.pp)
SELECT phid_pc,id s_tree_id,pid s_tree_pid,seq s_tree_no,htbh u_htbh,name s_tree_name,ywzb u_ywzb,zrcbzb u_zrcbzb,ewzb u_ewzb,htje u_htje,htje u_yjjsz,bykd u_bykd,bnljkd u_bnljkd,kgljkd u_kgljkd,byysgck u_byysgck,kgljysgck u_kgljysgck,0 u_byssgck,0 u_kgljssgck,'' u_htzt,(SELECT yy FROM p) tj_year,(SELECT mm FROM p) tj_mon FROM a ORDER BY CASE WHEN lv=0 THEN 1 WHEN lv=9 THEN 999 ELSE lv+1 END,seq;
